    <style>
        :root {
            /* Brand */
            --primary:           #137fec;
            --primary-hover:     #0f6fd4;
            --primary-subtle:    rgba(19,127,236,.12);
            --primary-glow:      rgba(19,127,236,.25);

            /* Surfaces */
            --bg-light:          #f1f5f9;
            --surface:           #ffffff;
            --text-main:         #0f172a;
            --text-secondary:    #64748b;
            --text-muted:        #94a3b8;
            --border:            #e2e8f0;

            /* Radii & shadows */
            --radius-xs:         6px;
            --radius-sm:         8px;
            --radius-md:         12px;
            --radius-lg:         16px;
            --shadow-xs:         0 1px 2px rgba(0,0,0,.06);
            --shadow-sm:         0 1px 4px rgba(0,0,0,.08), 0 1px 2px rgba(0,0,0,.04);
            --shadow-md:         0 4px 20px rgba(0,0,0,.10), 0 1px 4px rgba(0,0,0,.06);
            --shadow-lg:         0 12px 40px rgba(0,0,0,.14), 0 2px 8px rgba(0,0,0,.06);

            /* Aliases */
            --surface-light:     var(--surface);
            --border-light:      var(--border);

            /* Sidebar */
            --sidebar-bg:        #0c1526;
            --sidebar-hover:     rgba(255,255,255,.055);
            --sidebar-active-bg: rgba(19,127,236,.18);
            --sidebar-text:      rgba(255,255,255,.50);
            --sidebar-text-h:    rgba(255,255,255,.88);
            --sidebar-text-act:  #ffffff;
            --sidebar-divider:   rgba(255,255,255,.07);
            --sidebar-w:         248px;
            --sidebar-collapsed: 68px;

            /* Topbar */
            --topbar-h:          62px;
        }

        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

        body {
            font-family: 'Inter', sans-serif;
            background: var(--bg-light);
            color: var(--text-main);
            min-height: 100vh;
            overflow-x: hidden;
            -webkit-font-smoothing: antialiased;
        }

