        .topbar {
            position: fixed;
            top: 0; left: 0; right: 0;
            height: var(--topbar-h);
            display: flex;
            align-items: stretch;
            z-index: 1100;
        }

        /* Dark brand zone */
        .topbar-brand {
            width: var(--sidebar-w);
            flex-shrink: 0;
            background: var(--sidebar-bg);
            display: flex;
            align-items: center;
            padding-left: 1.125rem;
            overflow: hidden;
            white-space: nowrap;
            transition: width .25s cubic-bezier(.4,0,.2,1);
            border-right: 1px solid rgba(255,255,255,.06);
            border-bottom: 1px solid rgba(255,255,255,.06);
        }

        .topbar-brand-inner {
            display: flex;
            align-items: center;
            gap: .75rem;
            flex: 1;
            overflow: hidden;
            min-width: 0;
        }

        .topbar-logo-wrap {
            width: 34px; height: 34px;
            flex-shrink: 0;
            display: flex; align-items: center; justify-content: center;
        }
        .topbar-logo-wrap img {
            max-width: 100%; max-height: 100%;
            object-fit: contain;
            border-radius: 6px;
        }
        .topbar-logo-fallback {
            width: 34px; height: 34px;
            background: linear-gradient(135deg, var(--primary) 0%, #3b82f6 100%);
            border-radius: var(--radius-sm);
            display: flex; align-items: center; justify-content: center;
            flex-shrink: 0;
            box-shadow: 0 2px 8px rgba(19,127,236,.4);
        }
        .topbar-logo-fallback .material-symbols-outlined { font-size: 1.25rem; color: #fff; }

        .topbar-brand-name {
            font-size: .9375rem;
            font-weight: 700;
            color: #fff;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
            letter-spacing: -.015em;
            opacity: 1;
            transition: opacity .2s;
        }

        /* Toggle button */
        .sidebar-toggle {
            width: var(--topbar-h);
            height: var(--topbar-h);
            min-width: var(--topbar-h);
            display: flex; align-items: center; justify-content: center;
            background: transparent;
            border: none;
            color: rgba(255,255,255,.45);
            cursor: pointer;
            transition: background .15s, color .15s;
            flex-shrink: 0;
            margin-left: auto;
        }
        .sidebar-toggle:hover { background: rgba(255,255,255,.07); color: #fff; }
        .sidebar-toggle .material-symbols-outlined { font-size: 1.375rem; }

        /* White content zone */
        .topbar-content {
            flex: 1;
            background: var(--surface);
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 0 1.5rem;
            border-bottom: 1px solid var(--border);
            min-width: 0;
        }

        .topbar-left { display: flex; align-items: center; gap: .875rem; min-width: 0; }
        .topbar-right { display: flex; align-items: center; gap: .5rem; flex-shrink: 0; }

        .topbar-page-title {
            font-size: .9375rem;
            font-weight: 600;
            color: var(--text-main);
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }
        .topbar-divider {
            width: 1px; height: 1.25rem;
            background: var(--border);
            flex-shrink: 0;
        }

        /* Icon buttons in topbar */
        .topbar-btn {
            position: relative;
            width: 2.25rem; height: 2.25rem;
            display: flex; align-items: center; justify-content: center;
            border-radius: var(--radius-sm);
            border: 1.5px solid var(--border);
            background: transparent;
            color: var(--text-secondary);
            cursor: pointer;
            transition: all .15s;
            text-decoration: none;
        }
        .topbar-btn:hover { background: var(--bg-light); color: var(--primary); border-color: var(--primary-subtle); }
        .topbar-btn .material-symbols-outlined { font-size: 1.2rem; }
        /* Notification badge (count) */
        .notif-badge {
            position: absolute;
            top: -.2rem; right: -.2rem;
            min-width: 17px; height: 17px;
            background: #ef4444;
            color: #fff;
            border-radius: 999px;
            font-size: .6rem;
            font-weight: 800;
            line-height: 17px;
            text-align: center;
            padding: 0 .25rem;
            border: 1.5px solid var(--surface);
            pointer-events: none;
        }

        /* Notification panel dropdown */
        .notif-panel {
            min-width: 440px;
            max-width: 440px;
            padding: 0;
            margin-top: .375rem !important;
            border: 1px solid rgba(148, 163, 184, 0.18);
            border-radius: 22px;
            box-shadow: 0 24px 60px rgba(15, 23, 42, 0.16);
            overflow: hidden;
        }
        @media (max-width: 520px) { .notif-panel { min-width: calc(100vw - 2rem); max-width: calc(100vw - 2rem); } }
        .notif-panel-header {
            display: flex; align-items: center; justify-content: space-between;
            padding: 1rem 1.125rem;
            border-bottom: 1px solid var(--border);
            background: linear-gradient(180deg, #ffffff 0%, #f8fafc 100%);
            font-size: .875rem; font-weight: 700; color: var(--text-main);
        }
        .notif-mark-all {
            background: none; border: none; cursor: pointer;
            font-size: .8125rem; font-weight: 700; color: var(--primary); padding: 0;
        }
        .notif-mark-all:hover { text-decoration: underline; }
        .notif-list {
            max-height: 430px;
            overflow-y: auto;
            background: linear-gradient(180deg, #ffffff 0%, #f8fafc 100%);
        }
        .notif-item {
            display: flex; gap: .875rem;
            align-items: flex-start;
            padding: 1rem 1.125rem;
            border-bottom: 1px solid var(--border);
            cursor: pointer;
            transition: background .12s;
            text-decoration: none;
            color: inherit;
            position: relative;
        }
        .notif-item:last-child { border-bottom: none; }
        .notif-item:hover { background: #f8fafc; }
        .notif-item.unread {
            background: linear-gradient(90deg, rgba(37, 99, 235, 0.08), rgba(255, 255, 255, 0.98));
            box-shadow: inset 4px 0 0 #2563eb;
        }
        .notif-item.unread:hover { background: linear-gradient(90deg, rgba(37, 99, 235, 0.12), rgba(248, 250, 252, 1)); }
        .notif-item-icon {
            width: 42px; height: 42px; border-radius: 14px; flex-shrink: 0;
            display: flex; align-items: center; justify-content: center;
            box-shadow: 0 12px 22px rgba(15, 23, 42, 0.10);
        }
        .notif-item-icon .material-symbols-outlined { font-size: 1.1rem; color: #fff; font-variation-settings: 'FILL' 1; }
        .notif-item-body {
            flex: 1;
            min-width: 0;
            display: grid;
            gap: .28rem;
        }
        .notif-item-title {
            font-size: 1rem;
            font-weight: 700;
            color: var(--text-main);
            line-height: 1.3;
            letter-spacing: -.01em;
        }
        .notif-item-msg {
            font-size: .84rem;
            color: var(--text-secondary);
            line-height: 1.5;
            display: -webkit-box;
            -webkit-line-clamp: 2;
            -webkit-box-orient: vertical;
            overflow: hidden;
        }
        .notif-item-meta {
            display: flex;
            align-items: center;
            justify-content: space-between;
            gap: .75rem;
            margin-top: .2rem;
            font-size: .74rem;
            color: var(--text-muted);
        }
        .notif-item-time,
        .notif-item-date {
            line-height: 1.2;
            white-space: nowrap;
        }
        .notif-item-date {
            text-align: right;
        }
        .notif-empty { text-align: center; padding: 2rem 1rem; color: var(--text-muted); font-size: .875rem; }

        /* User dropdown */
        .user-btn {
            display: flex; align-items: center; gap: .5rem;
            padding: .3125rem .625rem .3125rem .375rem;
            border-radius: var(--radius-md);
            border: 1.5px solid var(--border);
            background: transparent;
            cursor: pointer;
            transition: all .15s;
            text-decoration: none;
        }
        .user-btn:hover { background: var(--bg-light); border-color: #cbd5e1; }
        .user-btn::after { display: none; }

        .user-avatar {
            width: 1.875rem; height: 1.875rem;
            border-radius: 50%;
            background: linear-gradient(135deg, var(--primary) 0%, #6366f1 100%);
            color: #fff;
            display: flex; align-items: center; justify-content: center;
            font-size: .6875rem;
            font-weight: 800;
            flex-shrink: 0;
            letter-spacing: .02em;
            overflow: hidden;
        }
        .user-avatar img {
            width: 100%; height: 100%;
            object-fit: cover;
            border-radius: 50%;
        }
        .user-info { line-height: 1.25; }
        .user-name { font-size: .8125rem; font-weight: 600; color: var(--text-main); }
        .user-role { font-size: .6875rem; color: var(--text-muted); text-transform: capitalize; }
        .user-chevron { font-size: .9375rem; color: var(--text-muted); margin-left: -.125rem; }

        .dropdown-menu {
            border: 1px solid var(--border);
            border-radius: var(--radius-md);
            box-shadow: var(--shadow-lg);
            padding: .375rem;
            min-width: 11rem;
            margin-top: .375rem !important;
        }
        .dropdown-item {
            border-radius: var(--radius-sm);
            font-size: .875rem;
            padding: .5625rem .75rem;
            display: flex; align-items: center; gap: .5rem;
            color: var(--text-main);
            transition: background .15s;
        }
        .dropdown-item .material-symbols-outlined { font-size: 1.125rem; color: var(--text-muted); }
        .dropdown-item:hover { background: var(--bg-light); color: var(--text-main); }
        .dropdown-item.text-danger { color: #dc2626 !important; }
        .dropdown-item.text-danger .material-symbols-outlined { color: #dc2626; }
        .dropdown-divider { border-color: var(--border); margin: .25rem 0; }

