        .sidebar {
            position: fixed;
            top: var(--topbar-h);
            left: 0; bottom: 0;
            width: var(--sidebar-w);
            background: var(--sidebar-bg);
            display: flex;
            flex-direction: column;
            overflow: hidden;
            transition: width .25s cubic-bezier(.4,0,.2,1);
            z-index: 1050;
            border-right: 1px solid rgba(255,255,255,.05);
        }

        /* Subtle gradient at top of sidebar */
        .sidebar::before {
            content: '';
            position: absolute;
            top: 0; left: 0; right: 0;
            height: 140px;
            background: linear-gradient(180deg, rgba(19,127,236,.06) 0%, transparent 100%);
            pointer-events: none;
        }

        .sidebar-nav {
            flex: 1;
            overflow-y: auto;
            overflow-x: hidden;
            padding: 1rem .625rem 0;
            scrollbar-width: thin;
            scrollbar-color: rgba(255,255,255,.08) transparent;
            position: relative;
        }
        .sidebar-nav::-webkit-scrollbar { width: 3px; }
        .sidebar-nav::-webkit-scrollbar-thumb { background: rgba(255,255,255,.1); border-radius: 2px; }

        /* Section label */
        .nav-section {
            margin-bottom: .25rem;
        }
        .nav-section + .nav-section {
            margin-top: .875rem;
        }
        .nav-section-label {
            font-size: .625rem;
            font-weight: 700;
            letter-spacing: .1em;
            text-transform: uppercase;
            color: rgba(255,255,255,.25);
            padding: .5rem .75rem .375rem;
            white-space: nowrap;
            overflow: hidden;
            opacity: 1;
            transition: opacity .2s;
        }

        /* Nav links */
        .nav-links { display: flex; flex-direction: column; gap: 2px; }

        .nav-link {
            display: flex;
            align-items: center;
            gap: .75rem;
            padding: .5625rem .75rem;
            border-radius: var(--radius-sm);
            color: var(--sidebar-text) !important;
            text-decoration: none;
            font-size: .875rem;
            font-weight: 500;
            white-space: nowrap;
            overflow: hidden;
            transition: background .15s, color .15s;
            position: relative;
            border: none;
            background: transparent;
            width: 100%;
            text-align: left;
            cursor: pointer;
            line-height: 1;
        }
        .nav-link .material-symbols-outlined {
            font-size: 1.25rem;
            flex-shrink: 0;
            color: rgba(255,255,255,.38);
            transition: color .15s;
            font-variation-settings: 'FILL' 0, 'wght' 300;
        }
        .nav-label {
            overflow: hidden;
            opacity: 1;
            transition: opacity .15s;
            white-space: nowrap;
            flex: 1;
        }

        .nav-link:hover {
            background: var(--sidebar-hover);
            color: var(--sidebar-text-h) !important;
        }
        .nav-link:hover .material-symbols-outlined {
            color: rgba(255,255,255,.75);
        }

        .nav-link.active {
            background: linear-gradient(90deg, rgba(19,127,236,.22) 0%, rgba(19,127,236,.08) 100%);
            color: var(--sidebar-text-act) !important;
            font-weight: 600;
        }
        .nav-link.active::before {
            content: '';
            position: absolute;
            left: 0; top: 50%;
            transform: translateY(-50%);
            height: 65%;
            width: 3px;
            background: linear-gradient(180deg, #60a5fa 0%, #137fec 100%);
            border-radius: 0 3px 3px 0;
        }
        .nav-link.active .material-symbols-outlined {
            color: #60a5fa;
            font-variation-settings: 'FILL' 1, 'wght' 400;
        }

        /* Badge on nav item (e.g. coming soon) */
        .nav-badge {
            margin-left: auto;
            font-size: .6rem;
            font-weight: 700;
            letter-spacing: .04em;
            text-transform: uppercase;
            padding: .15rem .45rem;
            border-radius: 999px;
            background: rgba(255,255,255,.08);
            color: rgba(255,255,255,.3);
            flex-shrink: 0;
        }

        /* Sidebar footer */
        .sidebar-footer {
            padding: .75rem .625rem .875rem;
            border-top: 1px solid var(--sidebar-divider);
            flex-shrink: 0;
        }
        .sidebar-footer .nav-link:hover {
            background: rgba(239,68,68,.12) !important;
            color: #fca5a5 !important;
        }
        .sidebar-footer .nav-link .material-symbols-outlined { color: rgba(255,255,255,.35); }
        .sidebar-footer .nav-link:hover .material-symbols-outlined { color: #fca5a5; }

