        body.sidebar-collapsed .topbar-brand        { width: var(--sidebar-collapsed); }
        body.sidebar-collapsed .sidebar             { width: var(--sidebar-collapsed); }
        body.sidebar-collapsed .main-content        { margin-left: var(--sidebar-collapsed); }

        body.sidebar-collapsed .topbar-brand-name,
        body.sidebar-collapsed .sidebar .nav-label,
        body.sidebar-collapsed .sidebar .nav-section-label,
        body.sidebar-collapsed .sidebar .nav-badge {
            opacity: 0;
            pointer-events: none;
            width: 0;
        }
        body.sidebar-collapsed .topbar-brand-inner {
            width: 0; overflow: hidden; flex: 0;
        }
        body.sidebar-collapsed .topbar-brand {
            padding-left: 0;
            justify-content: center;
        }
        body.sidebar-collapsed .sidebar-toggle { margin-left: 0; }

        body.sidebar-collapsed .nav-link,
        body.sidebar-collapsed .sidebar-footer .nav-link {
            justify-content: center;
            gap: 0;
            padding-left: 0;
            padding-right: 0;
        }
        body.sidebar-collapsed .nav-link::before { display: none; }

        /* Tooltip on collapsed icons */
        body.sidebar-collapsed .sidebar .nav-link {
            overflow: visible;
        }
        body.sidebar-collapsed .sidebar .nav-link[title]:hover::after {
            content: attr(title);
            position: absolute;
            left: calc(100% + 10px);
            top: 50%;
            transform: translateY(-50%);
            background: #1e293b;
            color: rgba(255,255,255,.9);
            font-size: .8rem;
            font-weight: 500;
            padding: .375rem .75rem;
            border-radius: 6px;
            white-space: nowrap;
            pointer-events: none;
            z-index: 2000;
            box-shadow: 0 4px 16px rgba(0,0,0,.35);
            border: 1px solid rgba(255,255,255,.06);
