        .page-title    { font-size: 1.625rem; font-weight: 900; letter-spacing: -.03em; margin-bottom: .25rem; color: var(--text-main); }
        .page-subtitle { font-size: .875rem; color: var(--text-secondary); margin-bottom: 1.75rem; line-height: 1.6; }

        /* Stat cards */
        .stat-card {
            background: var(--surface);
            border: 1px solid var(--border);
            border-radius: var(--radius-md);
            padding: 1.375rem 1.5rem;
            display: flex; align-items: center; gap: 1rem;
            box-shadow: var(--shadow-sm);
            transition: box-shadow .2s, transform .2s;
            position: relative;
            overflow: hidden;
        }
        .stat-card::after {
            content: '';
            position: absolute;
            top: 0; left: 0; right: 0;
            height: 3px;
            background: var(--stat-color, var(--primary));
            border-radius: var(--radius-md) var(--radius-md) 0 0;
        }
        .stat-card:hover { box-shadow: var(--shadow-md); transform: translateY(-2px); }
        .stat-icon {
            width: 3rem; height: 3rem;
            border-radius: var(--radius-sm);
            display: flex; align-items: center; justify-content: center;
            flex-shrink: 0;
        }
        .stat-icon .material-symbols-outlined { font-size: 1.5rem; }
        .stat-label { font-size: .8125rem; color: var(--text-secondary); font-weight: 500; margin-bottom: .25rem; }
        .stat-value { font-size: 1.75rem; font-weight: 900; letter-spacing: -.03em; line-height: 1; }

