        /* ═══════════════════════════════════════════════════════════════
           GLOBAL RESPONSIVE UTILITIES
           ═══════════════════════════════════════════════════════════════ */

        /* Responsive table scroll wrapper */
        .table-scroll {
            overflow-x: auto;
            -webkit-overflow-scrolling: touch;
        }
        .table-scroll > table { min-width: 560px; }

        /* Prevent iOS font-size zoom on inputs */
        input, select, textarea, .form-control, .form-select {
            font-size: 1rem;
        }

        /* Touch-friendly base for all interactive elements */
        .btn, button, .topbar-btn, .user-btn, a.btn {
            min-height: 2.25rem;
        }

        /* ── Tablet (≤ 991.98px) ─────────────────────────────────────── */
        @media (max-width: 991.98px) {
            .main-content { padding: 1.5rem 1.25rem 2rem; }

            /* 2-col grids on tablet */
            .stats-grid,
            .stats-grid-2,
            .quick-grid {
                grid-template-columns: repeat(2, 1fr) !important;
            }

            /* Forms: ensure inputs go full width */
            .row.g-3 > [class*="col-"]:not([class*="col-auto"]) {
                flex: 0 0 100%;
                max-width: 100%;
            }
        }

        /* ── Mobile (≤ 767.98px) ─────────────────────────────────────── */
        @media (max-width: 767.98px) {
            :root { --topbar-h: 58px; }

            /* Sidebar: off-screen drawer */
            .sidebar {
                transform: translateX(-100%);
                transition: transform .25s cubic-bezier(.4,0,.2,1), width .25s;
                width: var(--sidebar-w) !important;
            }

            /* Topbar adjustments */
            .topbar-brand { width: auto !important; padding-left: .75rem; }
            .topbar-brand-name { display: none; }
            .topbar-divider { display: none; }
            .user-info { display: none; }

            /* Main content full-width */
            .main-content { margin-left: 0 !important; padding: 1.25rem 1rem 2rem; }

            /* Typography */
            .page-title { font-size: 1.25rem; }
            h1 { font-size: 1.5rem; }
            h2 { font-size: 1.25rem; }
            h3 { font-size: 1.125rem; }

            /* Touch-friendly buttons */
            .btn, button, .topbar-btn, a.btn {
                min-height: 2.5rem;
                padding-top: .5rem;
                padding-bottom: .5rem;
            }
            .topbar-btn {
                padding: 0 .625rem;
                min-height: 2.25rem;
            }

            /* Dashboard stat grids */
            .stats-grid,
            .stats-grid-2,
            .kpi-grid,
            .quick-grid {
                grid-template-columns: repeat(2, 1fr) !important;
                gap: .75rem !important;
            }

            /* Welcome banner: stack vertically */
            .welcome-banner {
                flex-direction: column;
                align-items: flex-start;
                padding: 1.25rem 1.25rem;
            }
            .welcome-badge { margin-top: .5rem; }

            /* Card/surface padding reduction */
            .stat-card { padding: 1rem; }

            /* Page header: stack action buttons */
            .emp-header,
            .page-header,
            .filter-bar {
                flex-direction: column;
                align-items: flex-start;
            }
            .emp-header .btn-add-emp,
            .page-header .btn,
            .filter-bar .btn {
                width: 100%;
                justify-content: center;
            }

            /* Forms: full-width inputs and vertical stacking */
            .form-control,
            .form-select,
            select,
            input[type="text"],
            input[type="email"],
            input[type="password"],
            input[type="number"],
            input[type="date"],
            input[type="time"],
            textarea {
                width: 100%;
            }
            .row.g-3 > [class*="col-"] {
                flex: 0 0 100%;
                max-width: 100%;
            }
            .d-flex.gap-2.flex-wrap { flex-wrap: wrap !important; }
            .d-flex.gap-2.flex-wrap > * { flex: 1 1 auto; min-width: 0; }

            /* Modals: full-screen on mobile */
            .modal-dialog {
                margin: 0;
                max-width: 100vw;
                min-height: 100%;
            }
            .modal-content {
                border-radius: 0;
                min-height: 100svh;
            }
            .modal-body { overflow-y: auto; }
            .modal-dialog-centered { align-items: flex-end; }
            .modal-dialog-centered .modal-content {
                border-radius: var(--radius-md) var(--radius-md) 0 0;
                min-height: auto;
                max-height: 92svh;
                overflow-y: auto;
            }

            /* Filter bar inputs */
            .filter-bar .d-flex,
            .filter-bar form { flex-direction: column; width: 100%; }
            .filter-bar input,
            .filter-bar select { width: 100%; }

            /* Tables: always scrollable */
            div[style*="overflow-x"] { -webkit-overflow-scrolling: touch; }

            /* Notification panel: full width */
            .notif-panel {
                min-width: calc(100vw - 1rem) !important;
                max-width: calc(100vw - 1rem) !important;
                left: .5rem !important;
                right: .5rem !important;
            }
        }

        /* ── Small mobile (≤ 479px) ──────────────────────────────────── */
        @media (max-width: 479px) {
            .stats-grid,
            .stats-grid-2,
            .kpi-grid {
                grid-template-columns: 1fr 1fr !important;
            }
            .quick-grid {
                grid-template-columns: 1fr 1fr !important;
            }
            .main-content { padding: 1rem .75rem 2rem; }
            .stat-value { font-size: 1.375rem; }
        }
    </style>
    @stack('styles')
