        function notificationVisual(type, title = '') {
            const key = `${type || ''} ${title || ''}`.toLowerCase();

            if (key.includes('comment')) {
                return { icon: 'chat_bubble', color: '#f59e0b' };
            }
            if (key.includes('regularization')) {
                return { icon: 'history_toggle_off', color: '#7c3aed' };
            }
            if (key.includes('timesheet')) {
                return { icon: 'schedule', color: '#2563eb' };
            }
            if (key.includes('task')) {
                return { icon: 'task_alt', color: '#0f766e' };
            }

            return { icon: 'notifications', color: '#475569' };
        }

