        window.loadNotifications = function () {
            list.innerHTML = '<div class="notif-empty">Loading...</div>';
            fetch('{{ route("notifications.index") }}', { headers: { 'X-Requested-With': 'XMLHttpRequest' } })
                .then(r => r.json())
                .then(renderNotifications)
                .catch(() => { list.innerHTML = '<div class="notif-empty">Failed to load.</div>'; });
        };

        function renderNotifications(data) {
            setBadge(data.unread_count);
            const items = data.notifications;
            if (!items.length) {
                list.innerHTML = '<div class="notif-empty">You have no notifications.</div>';
                return;
            }
            list.innerHTML = items.map(n => {
                const visual = notificationVisual(n.type, n.title);

                return `
                <a class="notif-item ${n.is_read ? '' : 'unread'}"
                   href="${n.url || '#'}"
                   data-id="${n.id}"
                   data-read="${n.is_read}"
                   onclick="handleNotifClick(event, this)">
                    <div class="notif-item-icon" style="background:${visual.color};">
                        <span class="material-symbols-outlined">${visual.icon}</span>
                    </div>
                    <div class="notif-item-body">
                        <div class="notif-item-title">${escHtml(n.title)}</div>
                        <div class="notif-item-msg">${escHtml(n.message)}</div>
                        <div class="notif-item-meta">
                            <div class="notif-item-time">${escHtml(n.time)}</div>
                            <div class="notif-item-date">${escHtml(n.formatted_at)}</div>
                        </div>
                    </div>
                </a>`;
            }).join('');
        }

