        window.handleNotifClick = function (e, el) {
            const id   = el.dataset.id;
            const read = el.dataset.read === 'true';
            const url  = el.href;

            if (!read) {
                e.preventDefault();
                fetch(`/notifications/${id}/read`, {
                    method: 'POST',
                    headers: {
                        'X-CSRF-TOKEN': CSRF,
                        'X-Requested-With': 'XMLHttpRequest',
                    },
                })
                .then(() => {
                    el.classList.remove('unread');
                    el.dataset.read = 'true';
                    // Decrease badge
                    const cur = parseInt(badge.textContent || '0', 10);
                    setBadge(Math.max(0, cur - 1));
                    if (url && url !== '#' && url !== window.location.href) {
                        window.location.href = url;
                    }
                })
                .catch(() => { if (url && url !== '#') window.location.href = url; });
            }
            // If already read, follow the link normally (no preventDefault)
