    {{-- Hidden logout form reused by the idle timer --}}
    <form id="idleLogoutForm" action="{{ route('logout') }}" method="POST" style="display:none;">
        @csrf
    </form>

    <script>
    (function () {
        'use strict';

        // ── Configuration ──────────────────────────────────────────────────────
        const IDLE_MS   = {{ (int) config('session.lifetime') }} * 60 * 1000; // e.g. 15 min
        const WARN_MS   = 2 * 60 * 1000;   // show warning 2 min before expiry
        const PING_URL  = '{{ route('session.ping') }}';
        const TICK_MS   = 1000;             // countdown tick interval

        // ── State ──────────────────────────────────────────────────────────────
        let lastActivity  = Date.now();
        let warnShown     = false;
        let countdownSecs = Math.floor(WARN_MS / 1000);
        let tickTimer     = null;

        // ── DOM refs ───────────────────────────────────────────────────────────
        const modal       = document.getElementById('idleModal');
        const countdown   = document.getElementById('idleCountdown');
        const stayBtn     = document.getElementById('idleStayBtn');
        const logoutBtn   = document.getElementById('idleLogoutBtn');
        const logoutForm  = document.getElementById('idleLogoutForm');

        // ── Activity tracking (throttled: max once per second) ─────────────────
        let throttleTimer = null;
        function onActivity() {
            if (throttleTimer) return;
            throttleTimer = setTimeout(() => { throttleTimer = null; }, 1000);
            if (!warnShown) {
                lastActivity = Date.now();
            }
        }

        ['mousemove', 'mousedown', 'keydown', 'touchstart', 'scroll'].forEach(function (evt) {
            document.addEventListener(evt, onActivity, { passive: true });
        });

        // ── Idle check loop ────────────────────────────────────────────────────
        setInterval(function () {
            const idle = Date.now() - lastActivity;

            if (idle >= IDLE_MS) {
                // Time's up — submit logout form
                clearInterval(tickTimer);
                logoutForm.submit();
                return;
            }

            if (idle >= IDLE_MS - WARN_MS && !warnShown) {
                showWarning();
            }
        }, TICK_MS);

        // ── Warning modal ──────────────────────────────────────────────────────
        function showWarning() {
            warnShown     = true;
            countdownSecs = Math.floor((IDLE_MS - (Date.now() - lastActivity)) / 1000);
            renderCountdown();
            modal.style.display = 'flex';

            tickTimer = setInterval(function () {
                countdownSecs--;
                if (countdownSecs <= 0) {
                    clearInterval(tickTimer);
                    logoutForm.submit();
                    return;
                }
                renderCountdown();
            }, TICK_MS);
        }

        function hideWarning() {
            modal.style.display = 'none';
            warnShown = false;
            clearInterval(tickTimer);
            tickTimer = null;
        }

        function renderCountdown() {
            const m = Math.floor(countdownSecs / 60);
            const s = countdownSecs % 60;
            countdown.textContent = (m > 0 ? m + 'm ' : '') + s + 's';
        }

        // ── Buttons ────────────────────────────────────────────────────────────
        stayBtn.addEventListener('click', function () {
            stayBtn.disabled = true;
            stayBtn.textContent = 'Extending…';

            fetch(PING_URL, {
                headers: {
                    'X-Requested-With': 'XMLHttpRequest',
                    'X-CSRF-TOKEN': document.querySelector('meta[name="csrf-token"]').content,
                }
            })
            .then(function () {
                lastActivity = Date.now();
                hideWarning();
            })
            .catch(function () {
                // Ping failed — session likely already expired; logout cleanly
                logoutForm.submit();
            })
            .finally(function () {
                stayBtn.disabled = false;
                stayBtn.textContent = 'Stay Logged In';
            });
        });

        logoutBtn.addEventListener('click', function () {
            clearInterval(tickTimer);
            logoutForm.submit();
        });

    })();
    </script>
